external_knowledge:
- 'Celebrated' refers to the director with the highest number of Facebook likes;
- The director must have directed a movie in the 'Drama' genre;
- The director must also have an acting role in their own movie.

- "combined filmography" refers to the sum of the number of movies directed by the director and the number of movies acted in by the actor;
- "more than a mere solo effort" means the total count of movies they have been involved in together is greater than 1;
- "the pair having the highest combined film count" means the pair with the maximum total movie count is returned.

sql:
SELECT T1.director_name, T1.num_movies_directed
FROM directors T1
WHERE T1.num_movies_directed > (
  SELECT AVG(num_movies_acted_in)
  FROM actors
);

SELECT DISTINCT a.actor_name
FROM actors a
JOIN movie_actor ma ON a.actor_id = ma.actor_id;

SELECT MAX(likes) AS highest_facebook_likes
FROM (
    SELECT director_facebook_likes AS likes FROM directors
    UNION ALL
    SELECT actor_facebook_likes AS likes FROM actors
);

